CREATE TABLE IF NOT EXISTS suppliers (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), tax_id_encrypted text, normalized_tax_id_hash text, legal_name text NOT NULL, country_code text NOT NULL, address_encrypted text, supplier_type text NOT NULL DEFAULT 'BUSINESS', validation_status text NOT NULL DEFAULT 'UNVALIDATED', source text NOT NULL, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now());
CREATE UNIQUE INDEX IF NOT EXISTS suppliers_tax_hash_uq ON suppliers(tenant_id, normalized_tax_id_hash) WHERE normalized_tax_id_hash IS NOT NULL;
CREATE TABLE IF NOT EXISTS expense_categories (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), code text NOT NULL, label text NOT NULL, created_at timestamptz NOT NULL DEFAULT now());
CREATE UNIQUE INDEX IF NOT EXISTS expense_categories_code_uq ON expense_categories(tenant_id,code);
CREATE TABLE IF NOT EXISTS purchase_documents (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), supplier_id uuid NOT NULL REFERENCES suppliers(id), document_type text NOT NULL, document_number text NOT NULL, issue_date date NOT NULL, operation_date date, due_date date, paid_at timestamptz, currency text NOT NULL, tax_base numeric(20,6) NOT NULL, vat_amount numeric(20,6) NOT NULL, total_amount numeric(20,6) NOT NULL, withholding_amount numeric(20,6) NOT NULL DEFAULT 0, category_code text NOT NULL, description text, status text NOT NULL DEFAULT 'DRAFT', storage_key text NOT NULL, sha256 text NOT NULL, mime_type text NOT NULL, import_file_id uuid REFERENCES import_files(id), created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now());
CREATE UNIQUE INDEX IF NOT EXISTS purchase_documents_identity_uq ON purchase_documents(tenant_id,supplier_id,document_number,issue_date);
CREATE TABLE IF NOT EXISTS purchase_document_tax_lines (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), purchase_document_id uuid NOT NULL REFERENCES purchase_documents(id) ON DELETE CASCADE, tax_base numeric(20,6) NOT NULL, vat_rate numeric(10,6) NOT NULL, vat_amount numeric(20,6) NOT NULL, regime text NOT NULL, country_code text NOT NULL, deductibility text NOT NULL DEFAULT 'REVIEW');
CREATE TABLE IF NOT EXISTS expense_tax_profiles (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), category_code text NOT NULL, method text NOT NULL, irpf_percentage numeric(10,6) NOT NULL, vat_criterion text NOT NULL, effective_from date NOT NULL, effective_to date, version text NOT NULL, reference text NOT NULL, active boolean NOT NULL DEFAULT true);
CREATE UNIQUE INDEX IF NOT EXISTS expense_tax_profiles_version_uq ON expense_tax_profiles(tenant_id,category_code,version);
CREATE TABLE IF NOT EXISTS home_office_configurations (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), legal_entity_id uuid NOT NULL REFERENCES legal_entities(id), total_square_meters numeric(12,4) NOT NULL, affected_square_meters numeric(12,4) NOT NULL, calculated_percentage numeric(10,6) NOT NULL, declared_036_037 boolean NOT NULL DEFAULT false, effective_from date NOT NULL, evidence text, vat_criterion text NOT NULL DEFAULT 'CONSERVATIVE', warnings_accepted boolean NOT NULL DEFAULT false, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS expense_deductibility_decisions (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), purchase_document_id uuid NOT NULL REFERENCES purchase_documents(id), expense_tax_profile_id uuid REFERENCES expense_tax_profiles(id), rule_version text NOT NULL, inputs_snapshot jsonb NOT NULL, deductible_irpf_amount numeric(20,6) NOT NULL, deductible_vat_base numeric(20,6) NOT NULL, deductible_vat_amount numeric(20,6) NOT NULL, explanation jsonb NOT NULL, warnings jsonb NOT NULL DEFAULT '[]', status text NOT NULL, decided_at timestamptz NOT NULL DEFAULT now());
CREATE INDEX IF NOT EXISTS purchase_documents_tenant_period_idx ON purchase_documents(tenant_id,issue_date,status);
